package com.google.gson.protobuf;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.protobuf.DescriptorProtos.EnumValueOptions;
import com.google.protobuf.Descriptors.EnumValueDescriptor;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.Method;
import java.util.Collections;

class ProtoTypeAdapterTest {

  private ProtoTypeAdapter protoTypeAdapterName;
  private ProtoTypeAdapter protoTypeAdapterNumber;

  private EnumValueDescriptor enumValueDescriptorMock;
  private EnumValueOptions enumValueOptionsMock;

  @BeforeEach
  void setUp() {
    // Create ProtoTypeAdapter with enumSerialization = EnumSerialization.NAME
    protoTypeAdapterName = new ProtoTypeAdapter(
        ProtoTypeAdapter.EnumSerialization.NAME,
        null,
        null,
        Collections.emptySet(),
        Collections.emptySet()
    );

    // Create ProtoTypeAdapter with enumSerialization != EnumSerialization.NAME (e.g. NUMBER)
    protoTypeAdapterNumber = new ProtoTypeAdapter(
        ProtoTypeAdapter.EnumSerialization.NUMBER,
        null,
        null,
        Collections.emptySet(),
        Collections.emptySet()
    );

    enumValueDescriptorMock = mock(EnumValueDescriptor.class);
    enumValueOptionsMock = mock(EnumValueOptions.class);
  }

  @Test
  void testGetEnumValue_WhenEnumSerializationIsName_ReturnsCustomSerializedEnumValue() throws Exception {
    when(enumValueDescriptorMock.getOptions()).thenReturn(enumValueOptionsMock);
    when(enumValueDescriptorMock.getName()).thenReturn("ENUM_NAME");

    // Spy on protoTypeAdapterName to mock private method getCustSerializedEnumValue
    ProtoTypeAdapter spyAdapter = Mockito.spy(protoTypeAdapterName);

    // Use reflection to mock the private method getCustSerializedEnumValue
    Method getCustSerializedEnumValueMethod = ProtoTypeAdapter.class.getDeclaredMethod("getCustSerializedEnumValue", EnumValueOptions.class, String.class);
    getCustSerializedEnumValueMethod.setAccessible(true);

    // Use Mockito's doReturn with reflection proxy
    doReturn("customSerializedValue").when(spyAdapter).getClass()
        .getDeclaredMethod("getCustSerializedEnumValue", EnumValueOptions.class, String.class)
        .invoke(spyAdapter, enumValueOptionsMock, "ENUM_NAME");

    // Instead of above, use Mockito's doReturn with spy and reflection via doAnswer:
    // But since direct mocking of private method with doReturn(...).when(...) is not supported,
    // we use reflection to override the method via spy:
    // So better use Mockito's doReturn for spy with method invocation:
    // But since doReturn().when() for private methods is not supported, use a workaround with Mockito's doAnswer or reflection.

    // Workaround: Use Mockito's doAnswer to intercept call to getCustSerializedEnumValue
    // But this is complicated; easier to use Whitebox from Powermock or similar, but not allowed here.

    // Alternative: Use reflection to replace method temporarily (not trivial),
    // so instead, use spy and override the private method via subclassing:

    // Create anonymous subclass to override private method (via reflection):
    ProtoTypeAdapter spyWithOverride = new ProtoTypeAdapter(
        ProtoTypeAdapter.EnumSerialization.NAME,
        null,
        null,
        Collections.emptySet(),
        Collections.emptySet()
    ) {
      @Override
      @SuppressWarnings("unused")
      private String getCustSerializedEnumValue(EnumValueOptions options, String defaultValue) {
        return "customSerializedValue";
      }
    };
    // But private method cannot be overridden directly, so use reflection to invoke getEnumValue on this subclass:
    Method getEnumValueMethod = ProtoTypeAdapter.class.getDeclaredMethod("getEnumValue", EnumValueDescriptor.class);
    getEnumValueMethod.setAccessible(true);
    Object result = getEnumValueMethod.invoke(spyWithOverride, enumValueDescriptorMock);

    assertEquals("customSerializedValue", result);
  }

  @Test
  void testGetEnumValue_WhenEnumSerializationIsNotName_ReturnsEnumNumber() throws Exception {
    when(enumValueDescriptorMock.getNumber()).thenReturn(42);

    // Use reflection to invoke private getEnumValue on protoTypeAdapterNumber
    Method getEnumValueMethod = ProtoTypeAdapter.class.getDeclaredMethod("getEnumValue", EnumValueDescriptor.class);
    getEnumValueMethod.setAccessible(true);
    Object result = getEnumValueMethod.invoke(protoTypeAdapterNumber, enumValueDescriptorMock);

    assertEquals(42, result);
  }
}
